function Particles(){return(<div style={{position:"absolute",inset:0,overflow:"hidden",pointerEvents:"none"}}>{PD.map(p=><div key={p.id} style={{position:"absolute",left:p.x+"%",top:p.y+"%",width:p.s,height:p.s,borderRadius:"50%",background:p.gold?G:"rgba(255,255,255,.18)",opacity:p.gold?.55:.18,animation:"float "+p.dur+"s ease-in-out "+p.delay+"s infinite"}}/>)}</div>);}
function Navbar({setView,currency,setCurrency}){return(<nav style={{padding:"0 28px",height:64,display:"flex",alignItems:"center",justifyContent:"space-between",background:"rgba(7,7,7,.92)",backdropFilter:"blur(20px)",borderBottom:"1px solid rgba(201,168,76,.07)",position:"relative",zIndex:50}}><button className="ni" onClick={()=>setView("home")} style={{fontSize:18,fontFamily:"'Cormorant Garamond',serif",fontWeight:600,color:"#F0EDE5",letterSpacing:"0.05em",textTransform:"none"}}>RIFE <span style={{color:G}}>VIP</span></button><div style={{display:"flex",gap:18,alignItems:"center",flexWrap:"wrap"}}><button className="ni" onClick={()=>setView("home")}>Packages</button><button className="ni" onClick={()=>setView("booking")}>Book Now</button><button className="ni" onClick={()=>setView("migrate")}>Upgrade ID</button><button className="ni" onClick={()=>setView("dashboard")}>My Tickets</button><button className="ni" onClick={()=>setView("admin")} style={{color:"rgba(201,168,76,.45)"}}>Admin ↗</button><select value={currency} onChange={e=>setCurrency(e.target.value)} style={{background:"rgba(201,168,76,.08)",border:"1px solid rgba(201,168,76,.2)",color:G,borderRadius:4,padding:"5px 10px",fontSize:12,fontFamily:"'DM Sans',sans-serif",cursor:"pointer",outline:"none"}}>{Object.keys(CURR).map(k=><option key={k} value={k} style={{background:"#141414"}}>{k}</option>)}</select></div></nav>);}
function QRCode({ref_,size=140}){const cells=13;const seed=ref_.split("").reduce((a,c)=>a+c.charCodeAt(0),0);const grid=Array.from({length:cells*cells},(_,i)=>{const r=Math.floor(i/cells),c=i%cells;if((r<3&&c<3)||(r<3&&c>=cells-3)||(r>=cells-3&&c<3))return true;return(seed*(i+1)*31)%7<3;});return(<div style={{width:size,height:size,padding:10,background:"rgba(255,255,255,.04)",border:"1px solid rgba(201,168,76,.3)",borderRadius:8,position:"relative",overflow:"hidden",flexShrink:0}}><div style={{display:"grid",gridTemplateColumns:"repeat("+cells+",1fr)",gap:1.2,width:"100%",height:"100%"}}>{grid.map((f,i)=><div key={i} style={{background:f?G:"transparent",borderRadius:.5,aspectRatio:"1"}}/>)}</div><div style={{position:"absolute",left:10,right:10,height:2,background:"linear-gradient(90deg,transparent,"+G+",transparent)",animation:"scanLine 2s linear infinite",top:"50%"}}/></div>);}
function MiniCd({seconds}){const[left,setLeft]=useState(seconds);useEffect(()=>{if(left<=0)return;const id=setInterval(()=>setLeft(l=>Math.max(0,l-1)),1000);return()=>clearInterval(id);},[]);const m=Math.floor(left/60),s=left%60;return <span style={{color:left<300?"#f87171":G,fontWeight:600,fontFamily:"monospace",fontSize:14}}>{String(m).padStart(2,"0")}:{String(s).padStart(2,"0")}</span>;}
function Countdown({target}){const[t,setT]=useState({d:0,h:0,m:0,s:0});useEffect(()=>{const calc=()=>{const diff=Math.max(0,target-Date.now());setT({d:Math.floor(diff/86400000),h:Math.floor((diff%86400000)/3600000),m:Math.floor((diff%3600000)/60000),s:Math.floor((diff%60000)/1000)});};calc();const id=setInterval(calc,1000);return()=>clearInterval(id);},[target]);return(<div style={{display:"flex",gap:20,justifyContent:"center"}}>{[["d","Days"],["h","Hrs"],["m","Min"],["s","Sec"]].map(([k,l])=>(<div key={k} style={{textAlign:"center"}}><div className="serif gt" style={{fontSize:34,fontWeight:500,lineHeight:1}}>{String(t[k]).padStart(2,"0")}</div><div style={{fontSize:9,color:"rgba(240,237,229,.3)",letterSpacing:".2em",marginTop:5,textTransform:"uppercase"}}>{l}</div></div>))}</div>);}
function Confetti(){return(<div style={{position:"absolute",inset:0,pointerEvents:"none",overflow:"hidden",zIndex:5}}>{CF.map(c=><div key={c.id} style={{position:"absolute",left:c.x+"%",top:-20,width:c.size,height:c.size,background:c.col,borderRadius:c.id%2===0?"50%":1,animation:"confettiFall "+c.dur+"s "+c.delay+"s ease-in forwards",transform:"rotate("+c.rot+"deg)"}}/>)}</div>);}
function PW({children,maxW=900}){return <div style={{minHeight:"calc(100vh - 64px)",padding:"60px 20px"}}><div style={{maxWidth:maxW,margin:"0 auto"}}>{children}</div></div>;}
function FL({children}){return <label style={{fontSize:11,letterSpacing:".15em",color:"rgba(240,237,229,.45)",textTransform:"uppercase"}}>{children}</label>;}
