{step===1&&(<div><div style={{background:"rgba(201,168,76,.05)",border:"1px solid rgba(201,168,76,.14)",borderRadius:8,padding:"12px 18px",marginBottom:24,fontSize:13,color:"rgba(240,237,229,.55)",lineHeight:1.8}}>Required amount: <strong style={{color:G}}>${total.toLocaleString()}</strong> — Purchase gift cards totalling this value.</div><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(110px,1fr))",gap:12}}>{GIFT_CARDS.map(gc=><div key={gc.id} className="gc-card" onClick={()=>{setGcType(gc);setStep(2);}} style={{background:"rgba(255,255,255,.02)",border:"1px solid rgba(255,255,255,.07)"}}><div style={{fontSize:26,marginBottom:8}}>{gc.icon}</div><div style={{width:32,height:32,borderRadius:7,background:gc.col+"22",border:"1px solid "+gc.col+"44",margin:"0 auto 8px",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{width:16,height:3,background:gc.col,borderRadius:2}}/></div><div style={{fontSize:11,fontWeight:500,lineHeight:1.4,color:"rgba(240,237,229,.8)"}}>{gc.name}</div></div>)}</div></div>)}
